"use strict";jQuery.Class("Settings_Recruitment_Index_Js",{},{collectTransitions:function(){const t=[];return jQuery("#recruitmentSettingsContainer .js-transition-checkbox:checked").each(function(){const e=jQuery(this);t.push({from:e.data("from"),to:e.data("to")})}),t},registerRowActions:function(){const t=jQuery("#recruitmentSettingsContainer");t.on("click",".js-select-row",function(){const e=jQuery(this).data("from");t.find('.js-transition-checkbox[data-from="'+e+'"]').prop("checked",!0)}),t.on("click",".js-clear-row",function(){const e=jQuery(this).data("from");t.find('.js-transition-checkbox[data-from="'+e+'"]').prop("checked",!1)}),t.on("click",".js-select-col",function(){const e=jQuery(this).data("to");t.find('.js-transition-checkbox[data-to="'+e+'"]').prop("checked",!0)})},registerSave:function(){const t=this;jQuery("#recruitmentSettingsContainer").on("click",".js-save-transitions",function(){const e=t.collectTransitions();app.saveAjax("saveTransitions",{transitions:e}).done(function(t){const e=t&&t.result&&t.result.message?app.vtranslate(t.result.message):app.vtranslate("LBL_SAVE_TRANSITIONS_SUCCESS","Settings:Recruitment");Vtiger_Helper_Js.showPnotify({text:e,type:"success",animation:"show"}),window.location.reload()}).fail(function(){Vtiger_Helper_Js.showPnotify({text:app.vtranslate("LBL_SAVE_TRANSITIONS_FAILED","Settings:Recruitment"),type:"error"})})})},registerEvents:function(){this.registerRowActions(),this.registerSave()}}),jQuery(document).ready(function(){(new Settings_Recruitment_Index_Js).registerEvents()});